import React from 'react';
import { useConversation } from './hooks/useConversation';
import InputArea from './components/InputArea';

function App() {
  const { messages, isTyping, currentStep, handleUserAnswer, userData } = useConversation();
  
  // Get the latest bot message
  const latestBotMessage = messages.filter(m => m.sender === 'bot').slice(-1)[0]?.text;

  return (
    <div className="container" style={{ 
      display: 'flex', 
      flexDirection: 'column', 
      height: '100vh', 
      background: '#fafaf9', // Warmer off-white background
      overflow: 'hidden',
      fontFamily: "'Inter', sans-serif" 
    }}>
      
      {/* Gentle Header */}
      <div style={{ 
        position: 'fixed', top: '40px', width: '100%', textAlign: 'center', 
        color: '#94a3b8', fontSize: '12px', letterSpacing: '4px', zIndex: 10 
      }}>
        CONFIDENTIAL INTAKE
      </div>

      <main style={{ 
        flex: 1, 
        display: 'flex', 
        flexDirection: 'column', 
        justifyContent: 'center', // Centers perfectly vertically
        alignItems: 'center', 
        padding: '20px',
        width: '100%'
      }}>
        
        {!currentStep && !isTyping ? (
          /* The Calming Thank You Screen */
          <div className="fade-in" style={{ textAlign: 'center', maxWidth: '500px' }}>
            <div style={{ fontSize: '60px', marginBottom: '20px' }}>🌿</div>
            <h2 style={{ color: '#1e293b', fontSize: '32px', marginBottom: '16px', fontWeight: '500' }}>
              Thank you, {userData.name}.
            </h2>
            <p style={{ color: '#64748b', fontSize: '18px', lineHeight: '1.6' }}>
              Your space is prepared. Your counselor will review these notes so you can focus entirely on your session.
            </p>
          </div>
        ) : (
          /* Active Question Area */
          <div style={{ width: '100%', maxWidth: '700px', textAlign: 'center' }}>
            
            {/* The Breathing Indicator or The Question */}
            <div style={{ minHeight: '120px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              {isTyping ? (
                <div className="breathing-indicator" />
              ) : (
                <h1 className="fade-in" key={latestBotMessage} style={{ 
                  fontSize: 'clamp(1.8rem, 4vw, 2.5rem)', 
                  color: '#334155',
                  fontWeight: '400',
                  lineHeight: '1.4',
                  margin: 0
                }}>
                  {latestBotMessage}
                </h1>
              )}
            </div>

            {/* Input Area (Only shows when not typing) */}
            <div style={{ 
              marginTop: '50px', 
              opacity: isTyping ? 0 : 1, 
              transition: 'opacity 0.5s ease',
              pointerEvents: isTyping ? 'none' : 'auto' 
            }}>
              <InputArea 
                currentStep={currentStep} 
                onSendMessage={handleUserAnswer} 
                isTyping={isTyping} 
              />
            </div>
          </div>
        )}
      </main>

      {/* Soft Progress Bar */}
      <div style={{ 
        position: 'fixed', bottom: '0', left: '0', height: '4px', 
        background: 'linear-gradient(90deg, #34d399, #10b981)', 
        transition: 'width 1.5s cubic-bezier(0.4, 0, 0.2, 1)', 
        width: `${currentStep ? (Object.keys(userData).length / 15) * 100 : 100}%` 
      }} />
    </div>
  );
}

export default App;
